// TIER 1: Filter for accounts that need research today
const accounts = $input.all();
const today = new Date();

const accountsToResearch = accounts
  .map(item => item.json)
  .filter(account => {
    // Skip if status is 'completed' or 'contacted'
    if (account.status === 'completed' || account.status === 'contacted') {
      return false;
    }

    // Include if never researched OR last research > 30 days ago
    if (!account.last_research_date) {
      return true;
    }

    const lastResearch = new Date(account.last_research_date);
    const daysSince = (today - lastResearch) / (1000 * 60 * 60 * 24);
    return daysSince > 30;
  })
  .slice(0, 10); // TIER 1: Limit to 10 per day to avoid rate limits

console.log(`${accountsToResearch.length} accounts selected for research today`);

return accountsToResearch.map(account => ({ json: account }));

// TIER 1: Extract and format research results
const accountData = $('Process Each Account').first().json;
const researchResult = $input.first().json;

// Check if research was successful
if (!researchResult.success) {
  console.error(`Research failed for ${accountData.company_name}:`, researchResult.error);
  return [{
    json: {
      company_name: accountData.company_name,
      status: 'research_failed',
      error: researchResult.error,
      timestamp: new Date().toISOString()
    }
  }];
}

// Format successful research data
return [{
  json: {
    // Original account data
    company_id: accountData.id || accountData.company_name.toLowerCase().replace(/\s+/g, '_'),
    company_name: accountData.company_name,
    industry: accountData.industry,
    target_role: accountData.target_role,

    // Research results from Tier 3 agent
    decision_maker_name: researchResult.decision_maker?.name || '',
    decision_maker_title: researchResult.decision_maker?.title || '',
    decision_maker_email: researchResult.decision_maker?.email || '',
    decision_maker_linkedin: researchResult.decision_maker?.linkedin_url || '',

    company_size: researchResult.company_info?.size || '',
    company_funding: researchResult.company_info?.funding || '',
    company_tech_stack: researchResult.company_info?.tech_stack?.join(', ') || '',

    pain_points: researchResult.pain_points?.join('; ') || '',
    buying_signals: researchResult.buying_signals?.join('; ') || '',

    // Metadata
    research_date: new Date().toISOString(),
    research_status: 'completed',
    ready_for_outreach: researchResult.decision_maker?.email ? true : false
  }
}];

// TIER 1: Generate summary report
const allResults = $input.all();

const summary = {
  total_processed: allResults.length,
  ready_for_outreach: allResults.filter(r => r.json.ready_for_outreach).length,
  needs_followup: allResults.filter(r => !r.json.ready_for_outreach).length,
  companies: allResults.map(r => ({
    name: r.json.company_name,
    status: r.json.research_status,
    decision_maker: r.json.decision_maker_name
  })),
  workflow_completed_at: new Date().toISOString()
};

console.log('Daily lead research completed:', summary);

return [{ json: summary }];
